<template>
  <div class="start-page" @click="redirectBasedOnDevice">
    <el-container>
      <el-main>
        <div class="welcome-container">
          <h1 class="welcome-text">Welcome to</h1>
          <h1 class="welcome-text">Lysssyo's Page!</h1>

        </div>
      </el-main>
    </el-container>
  </div>
</template>

<script>
export default {
  name: 'StartPage',
  methods: {
    redirectBasedOnDevice() {
      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
      const currentRoute = this.$router.currentRoute;
      if (currentRoute.path !== '/mobileAlgorithm' && currentRoute.path !== '/FrontView') {
        if (isMobile) {
          this.$router.push({ path: '/FrontView' });
        } else {
          this.$router.push({ path: '/FrontView' });
        }
      }
    },
    handleKeyDown(event) {
      if (event.key === 'Enter') {
        this.redirectBasedOnDevice(); // 直接跳转到 /emp 页面
      }
    }
  },
  mounted() {
    setTimeout(() => {
      this.redirectBasedOnDevice();
    }, 1000); // 延迟1秒后跳转
    // 监听键盘事件
    document.addEventListener('keydown', this.handleKeyDown);
  },
  destroyed() {
    // 组件销毁时移除键盘事件监听
    document.removeEventListener('keydown', this.handleKeyDown);
  }
};
</script>

<style>
.start-page {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  cursor: pointer; /* 添加光标样式以指示点击 */
}

.welcome-container {
  text-align: center;
}

.welcome-text {
  font-size: 20px;
  font-weight: bold;
  color: #333;
  margin: 0px;
}

/* Add this style to center the dialog box */
.el-message-box__wrapper {
  display: flex;
  justify-content: center;
  align-items: center;
  overflow: auto;
}

.el-message-box {
  max-width: 90%; /* 调整对话框的最大宽度 */
}

/* Media query for small screens */
@media (max-width: 768px) {
  .el-message-box {
    max-width: 100%; /* 调整小屏幕上对话框的最大宽度 */
  }
}
</style>
